+fn derive_repo_root(fixture_root: &Path) -> Result<PathBuf, String> {
+    fixture_root
+        .parent()
+        .and_then(Path::parent)
+        .and_then(Path::parent)
+        .map(Path::to_path_buf)
+        .ok_or_else(|| {
+            format!(
+                "unable to derive repository root from fixture_root {}",
+                fixture_root.display()
+            )
+        })
